<template>
  <div class="container-fluid">
    <div class="row">
        <div class="col-12 col-md-12">
            <div class="row">
                <div class="col-12 m-3">
                    <h2>
                        <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" fill="currentColor" class="bi bi-box-arrow-in-down" viewBox="0 0 16 16">
                        <path fill-rule="evenodd" d="M3.5 6a.5.5 0 0 0-.5.5v8a.5.5 0 0 0 .5.5h9a.5.5 0 0 0 .5-.5v-8a.5.5 0 0 0-.5-.5h-2a.5.5 0 0 1 0-1h2A1.5 1.5 0 0 1 14 6.5v8a1.5 1.5 0 0 1-1.5 1.5h-9A1.5 1.5 0 0 1 2 14.5v-8A1.5 1.5 0 0 1 3.5 5h2a.5.5 0 0 1 0 1h-2z"/>
                        <path fill-rule="evenodd" d="M7.646 11.854a.5.5 0 0 0 .708 0l3-3a.5.5 0 0 0-.708-.708L8.5 10.293V1.5a.5.5 0 0 0-1 0v8.793L5.354 8.146a.5.5 0 1 0-.708.708l3 3z"/>
                        </svg>
                        添加新商品
                    </h2>
                    
                </div>
            </div>
            <div>
                <div class="mb-3">
                    <label for="newProductName" class="form-label">商品名稱</label>
                    <input v-model="productName" type="text" class="form-control" id="newProductName" required>
                </div> 
                <div class="mb-3">
                    <label for="productDesc" class="form-label">商品描述</label>
                    <input v-model="productDesc" type="text" class="form-control" id="productDesc" placeholder="描述商品...">
                </div> 
                <div class="mb-3">
                    <label for="productPrice" class="form-label">商品價格</label>
                    <input  v-model.number="productPrice" type="text" class="form-control" id="productPrice" required >
                </div> 
                <div class="mb-3">
                    <label for="productStock" class="form-label">商品庫存</label>
                    <input  v-model.number="productStock" type="text" class="form-control" id="productStock" required>
                </div> 
                <div class="mb-3">
                    <label for="category" class="form-label">商品類別</label>
                    <input v-model="category" type="text" class="form-control" id="category" required>
                </div> 
                <div class="mb-3">
                    <label for="productImg" class="form-label">商品圖片</label>
                    <input v-model="productImg" type="text" class="form-control" id="productImg" placeholder="請輸入網址" required>
                </div> 
            </div>
            <div class="row">
                <div class="col-12 col-md-12">
                    <button id="submitBtn" @click="submitAddProduct" class="btn btn-success w-100 mb-3">
                        <template v-if="!submiting">
                            <div>
                                新增商品
                            </div>
                        </template>
                        <template v-if="submiting">
                            <div>
                                <div class="spinner-border" role="status">
                                    <span class="visually-hidden">Loading...</span>
                                </div>
                            </div>
                        </template>
                    </button>
                    <div v-if="isSubmitSuccess" class="alert alert-success text-center" role="alert">
                        商品新增成功
                    </div>
                    <div v-if="submitFailed" class="alert alert-danger" role="alert">
                        商品新增失敗！請正確填寫每一欄位
                    </div>
                </div>
            </div>
                
        </div>
    </div>
  </div>
</template>

<script>
import {reactive,toRefs,watch,ref,toRaw} from 'vue'
import axios from 'axios'
export default {
  name:'BackEndAddProduct',
  setup(){
    let submiting=ref(false)
    let submitFailed=ref(false)
    let isSubmitSuccess=ref(false)
    let product = reactive({
        productName:'',
        productDesc:'',
        productPrice:'',
        productStock:'',
        category:'',
        productImg:'',
    })


    function submitAddProduct(){
        submiting.value=true
        this.submitFailed=false
        for(let detail in product){
           if(product[detail]===''){
            this.submitFailed=true
            submiting.value=false
               return
           }
        }
        
        
        axios.post('/addproductentity',toRaw(product),{headers:{'contentType':'application/jason'}}).then(
            () => {
                isSubmitSuccess.value=true
                submiting.value=false
                for(let detail in product){
                    product[detail]=''
                }
            }
        )        

    }
    
   watch(()=>product.productPrice,()=>{
    if(!/^[1-9]\d*$/.test(product.productPrice)){
        product.productPrice=''
    }
   },{deep:true})

   watch(()=>product.productStock,()=>{
    if(!/^[1-9]\d*$/.test(product.productStock)){
        product.productStock=''
    }
   },{deep:true})

   



    return{
        ...toRefs(product),
        isSubmitSuccess,
        submitAddProduct,
        submiting,
        submitFailed
    }
    }
    
}
</script>

